import{_ as e,o as a,c as r,S as s}from"./chunks/framework.DZlzLDBr.js";const u=JSON.parse('{"title":"Scheduling","description":"","frontmatter":{},"headers":[],"relativePath":"Scheduling.md","filePath":"Scheduling.md","lastUpdated":null}'),d={name:"Scheduling.md"};function n(o,t,i,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="scheduling" tabindex="-1">Scheduling <a class="header-anchor" href="#scheduling" aria-label="Permalink to &quot;Scheduling&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sprout uses <strong>FSRS</strong> (Free Spaced Repetition Scheduler).</p><p>FSRS chooses future review dates per card, based on your past answers and elapsed time.</p><h2 id="how-fsrs-works" tabindex="-1">How FSRS works <a class="header-anchor" href="#how-fsrs-works" aria-label="Permalink to &quot;How FSRS works&quot;">​</a></h2><p>Each card tracks 3 values:</p><table tabindex="0"><thead><tr><th>Value</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Stability</strong></td><td>How long memory lasts before dropping to target retention</td></tr><tr><td><strong>Difficulty</strong></td><td>How hard the card is for you (0–10)</td></tr><tr><td><strong>Retrievability</strong></td><td>Estimated chance (0–1) you can recall it right now</td></tr></tbody></table><p>When you rate a card, FSRS:</p><ol><li>Updates difficulty and stability.</li><li>Calculates a next interval to meet your requested retention.</li><li>Schedules the due date.</li></ol><p>In practice, easy cards get longer intervals; forgotten cards get shorter intervals.</p><h2 id="card-stages" tabindex="-1">Card stages <a class="header-anchor" href="#card-stages" aria-label="Permalink to &quot;Card stages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Stage</th><th>Description</th></tr></thead><tbody><tr><td><strong>New</strong></td><td>Never reviewed</td></tr><tr><td><strong>Learning</strong></td><td>Early short-interval steps</td></tr><tr><td><strong>Review</strong></td><td>Main long-interval stage</td></tr><tr><td><strong>Relearning</strong></td><td>Short steps after a failed review</td></tr></tbody></table><h2 id="presets" tabindex="-1">Presets <a class="header-anchor" href="#presets" aria-label="Permalink to &quot;Presets&quot;">​</a></h2><p>Choose a preset in <strong>Settings → Study → Scheduling</strong> or set values manually:</p><table tabindex="0"><thead><tr><th>Preset</th><th>Learning steps</th><th>Relearning steps</th><th>Retention</th></tr></thead><tbody><tr><td>Relaxed</td><td>20 min</td><td>20 min</td><td>0.88</td></tr><tr><td>Balanced</td><td>10 min, 1 day</td><td>10 min</td><td>0.90</td></tr><tr><td>Aggressive</td><td>5 min, 30 min, 1 day</td><td>10 min</td><td>0.92</td></tr><tr><td>Custom</td><td><em>(user-defined)</em></td><td><em>(user-defined)</em></td><td><em>(user-defined)</em></td></tr></tbody></table><h3 id="manual-options" tabindex="-1">Manual options <a class="header-anchor" href="#manual-options" aria-label="Permalink to &quot;Manual options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Learning steps</td><td><code>10, 1440</code></td><td>Minutes between learning steps (comma-separated)</td></tr><tr><td>Relearning steps</td><td><code>10</code></td><td>Minutes between relearning steps</td></tr><tr><td>Requested retention</td><td>0.90</td><td>Target recall probability (0.80–0.97)</td></tr></tbody></table><h3 id="what-the-settings-mean" tabindex="-1">What the settings mean <a class="header-anchor" href="#what-the-settings-mean" aria-label="Permalink to &quot;What the settings mean&quot;">​</a></h3><ul><li><strong>Learning steps</strong>: short intervals for new cards before they move to Review.</li><li><strong>Relearning steps</strong>: short intervals after an Again on a Review card.</li><li><strong>Requested retention</strong>: target recall when card is due.</li></ul><p>Higher retention increases workload (more frequent reviews). Lower retention reduces workload but increases forgetting.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>0.90</strong> is a strong default for most users.</p></div><h2 id="fsrs-console-log" tabindex="-1">FSRS console / log <a class="header-anchor" href="#fsrs-console-log" aria-label="Permalink to &quot;FSRS console / log&quot;">​</a></h2><p>You can inspect a card&#39;s FSRS history:</p><ol><li>Open the <a href="./Card-Browser">Card Browser</a>.</li><li>Select a card.</li><li>Open card details to see ratings, stability, difficulty, and interval calculations.</li></ol><p>Use this if a due date looks unexpected.</p><h2 id="reset-options" tabindex="-1">Reset options <a class="header-anchor" href="#reset-options" aria-label="Permalink to &quot;Reset options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Effect</th></tr></thead><tbody><tr><td>Reset scheduling</td><td>Reset all cards to <strong>New</strong> (clears intervals, stability, difficulty)</td></tr><tr><td>Reset analytics</td><td>Clear review history and heatmap data</td></tr></tbody></table><p>Both options are in <strong>Settings → Reset</strong> and cannot be undone.</p>',29)])])}const p=e(d,[["render",n]]);export{u as __pageData,p as default};
